#include <bits/stdc++.h>using namespace std;#define int long long int#define all(x) x.begin(), x.end() void solve() {    int n, m; cin >> n >> m;    vector<int> vec[n + 1];    for (int i = 0; i < n; i++) {        int x, y; cin >> x >> y;        vec[y].push_back(x);    }     vector<int> pre(n + 1);    priority_queue<int, vector<int>, greater<int>> pq;    int ans = 0, sum = 0;    for (int i = n; i >= 0; i--) {        for (auto x : vec[i]) pq.push(x), sum += x;         while (pq.size() > i + 1) sum -= pq.top(), pq.pop();        ans = max(ans, sum);        pre[i] = sum;        if (pq.size() == i + 1) pre[i] -= pq.top();    }     //for(auto x : pre) cout << x << ' '; cout << '\n';    for (int i = 1; i <= n; i++) pre[i] = max(pre[i], pre[i - 1]);    for (int i = 0; i < m; i++) {        int x, y; cin >> x >> y;        cout << max(ans, pre[y] + x) << ' ';    }    cout << '\n';}int32_t main() {    ios_base::sync_with_stdio(0); cin.tie(0);    int t = 1; cin >> t;    while (t--) solve();    return 0;}